#include <vector>
#include <queue>

using namespace std;

long long solve(vector<vector<long long>> grid, long long k) {
    if (grid.empty() || grid[0].empty()) return 0;
    int m = grid.size();
    int n = grid[0].size();
    vector<vector<bool>> visited(m, vector<bool>(n, false));
    int directions[4][2] = {{-1, 0}, {1, 0}, {0, -1}, {0, 1}};
    long long count = 0;

    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            if (grid[i][j] > 0 && !visited[i][j]) {
                queue<pair<int, int>> q;
                q.push({i, j});
                visited[i][j] = true;
                long long sum = grid[i][j];

                while (!q.empty()) {
                    auto current = q.front();
                    q.pop();
                    int x = current.first;
                    int y = current.second;

                    for (auto dir : directions) {
                        int nx = x + dir[0];
                        int ny = y + dir[1];

                        if (nx >= 0 && nx < m && ny >= 0 && ny < n && grid[nx][ny] > 0 && !visited[nx][ny]) {
                            visited[nx][ny] = true;
                            sum += grid[nx][ny];
                            q.push({nx, ny});
                        }
                    }
                }

                if (sum % k == 0) {
                    count++;
                }
            }
        }
    }

    return count;
}
